package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.Dienstverband;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.dmfa.Eredienst;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.Comparator;
import java.util.EnumSet;
import java.util.Optional;
import java.util.Set;

@AllArgsConstructor
public class VakbondsPremieOpdracht {

    private static final int PREMIE_MONTH = 3;
    private static final int PREMIE_DAY = 31;
    private static final int GEDETACHEERD_2 = 2;

    // dmfa statuut not in (B(2), VA (18), EC (21))
    private static final Set<DmfapplStatuutDmfappl> GEEN_VAKBONDSPREMIE_STATUUT = ImmutableSet.<DmfapplStatuutDmfappl>builder()
            .add(DmfapplStatuutDmfappl.VRIJWILLIGEAMBULANCIER)
            .add(DmfapplStatuutDmfappl.VRIJWILLIGE_BRANDWEER)
            .add(DmfapplStatuutDmfappl.PERSONEEL_ONDERWIJS_GEEN_DIMONA)
            .addAll(Eredienst.getErediensten())
            .build();

    // Werkgeverscategorie in 750,751,752,753 of 754
    private static final EnumSet<WerkgeversCategorie> VAKBONDSPREMIE_WERKGEVERSCATEGORIE = EnumSet.of(
            WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_OPENBAAR_DMFA,
            WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENB_ARBREG_OPENBAAR_DMFA,
            WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_PRIVE_DMFA,
            WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_OPENB_ARBREG_PRIVE_DMFA,
            WerkgeversCategorie.LOKALE_POLITIEZONE);

    // Werknemerskengetal not in (840,841,404,405,046,047,497,876,877,879)
    private static final EnumSet<DmfapplWnkengetal> GEEN_VAKBONDSPREMIE_KENGETAL = EnumSet.of(
            DmfapplWnkengetal.STUDENTEN_ARBEIDER,
            DmfapplWnkengetal.STUDENTEN_BEDIENDEN,
            DmfapplWnkengetal.LOKALE_MANDATARIS_NIET_BECHERMD_DMFA,
            DmfapplWnkengetal.LOKALE_MANDATARIS_BESCHERMD,
            DmfapplWnkengetal.ANDERE_KUNSTENAARS,
            DmfapplWnkengetal.LEERPLICHTIGE_KUNSTENAARS,
            DmfapplWnkengetal.ERKENDE_ONTHAALOUDERS,
            DmfapplWnkengetal.ONTSLAGEN_STATUTAIR_ZIEKTE,
            DmfapplWnkengetal.ONTSLAGEN_STATUTAIR_WERKLOOS,
            DmfapplWnkengetal.BRUGGEPENSIONEERDE);

    private VakbondspremieMraVoorwaarden mraVoorwaarden;
    private Set<Opdracht> opdrachten;
    private RekenTijd rekenTijd;

    private static boolean heeftVakbondspremieOpper(Opdracht opdracht, LocalDate premieDate) {
        return opdracht.getOpperSlices().stream()
                .anyMatch(opper -> opper.getActualInterval().contains(premieDate)
                        && heeftVakbondspremieRszppo(opper.getRszppo()));
    }

    private static boolean heeftVakbondspremieRszppo(Rszppo rszppo) {
        // Werkgeverscategorie in 750,751,752,753 of 754
        // Werknemerskengetal not in (840,841,404,405,046,047,497,876,877,879)
        // dmfa statuut not in (B(2), VA (18), EC (21))
        // gedetacheerd not 2
        // controleer dienstverband 1
        boolean isDienstVerbandNietGedetacheerd2 = rszppo.getDienstverband() == Dienstverband.JA
                && rszppo.getGedetacheerd() != GEDETACHEERD_2;
        return isDienstVerbandNietGedetacheerd2
                && !GEEN_VAKBONDSPREMIE_STATUUT.contains(rszppo.getStatuutDmfappl())
                && VAKBONDSPREMIE_WERKGEVERSCATEGORIE.contains(rszppo.getWerkgeversCategorie())
                && !GEEN_VAKBONDSPREMIE_KENGETAL.contains(rszppo.getWerknemersKengetal());
    }

    public Optional<Opdracht> bepaal() {
        LocalDate premieDate = getPremieDate();
        return opdrachten.stream()
                .filter(opdracht -> opdracht.getPeriode().contains(premieDate))
                .filter(opdracht -> heeftVakbondspremieOpper(opdracht, premieDate))
                .filter(mraVoorwaarden::test)
                .min(Comparator.comparingInt(Opdracht::getOpdrachtnr));
    }

    private LocalDate getPremieDate() {
        int jaar = rekenTijd.getRekenYear();
        return new LocalDate(jaar, PREMIE_MONTH, PREMIE_DAY);
    }
}
